//! Residual dictionary loader + dict-mode encode wrapper.
//!
//! Loads a .bwdict file produced by `build-residual-dict` and exposes
//! `encode_residual_with_dict(bytes) -> Vec<u8>` that routes through
//! `bitwise::bw_codec::encode_bw` with the dictionary set in
//! `EncodeBwOptions`.
//!
//! Env-gated: `GNOSIS_RESIDUAL_DICT=/path/to/file.bwdict` loads the
//! dictionary at first call; unset = no dict, encode falls back to
//! plain bw-codec.

#![allow(dead_code)]

use std::fs::File;
use std::io::Read;
use std::path::Path;
use std::sync::OnceLock;

use bitwise::bw_codec::{encode_bw, BwError, EncodeBwOptions};

#[derive(Debug, Clone, PartialEq)]
pub struct ResidualDict {
    pub entry_len: u32,
    pub entries: Vec<Vec<u8>>,
}

#[derive(Debug)]
pub enum DictLoadError {
    Io(std::io::Error),
    BadMagic,
    BadVersion(u32),
    Truncated,
}

impl From<std::io::Error> for DictLoadError {
    fn from(e: std::io::Error) -> Self {
        Self::Io(e)
    }
}

impl ResidualDict {
    pub fn load(path: &Path) -> Result<Self, DictLoadError> {
        let mut file = File::open(path)?;
        let mut buf = Vec::new();
        file.read_to_end(&mut buf)?;
        Self::from_bytes(&buf)
    }

    pub fn from_bytes(buf: &[u8]) -> Result<Self, DictLoadError> {
        if buf.len() < 16 {
            return Err(DictLoadError::Truncated);
        }
        if &buf[..4] != b"BWDC" {
            return Err(DictLoadError::BadMagic);
        }
        let version = u32::from_le_bytes([buf[4], buf[5], buf[6], buf[7]]);
        if version != 1 {
            return Err(DictLoadError::BadVersion(version));
        }
        let count = u32::from_le_bytes([buf[8], buf[9], buf[10], buf[11]]) as usize;
        let entry_len = u32::from_le_bytes([buf[12], buf[13], buf[14], buf[15]]);
        let elen = entry_len as usize;
        let expected = 16 + count * elen;
        if buf.len() < expected {
            return Err(DictLoadError::Truncated);
        }
        let mut entries = Vec::with_capacity(count);
        for i in 0..count {
            let start = 16 + i * elen;
            entries.push(buf[start..start + elen].to_vec());
        }
        Ok(Self { entry_len, entries })
    }
}

/// Global dictionary loaded lazily on first call.
static GLOBAL_DICT: OnceLock<Option<ResidualDict>> = OnceLock::new();

pub fn global_dict() -> Option<&'static ResidualDict> {
    GLOBAL_DICT
        .get_or_init(|| {
            std::env::var("GNOSIS_RESIDUAL_DICT")
                .ok()
                .and_then(|p| ResidualDict::load(Path::new(&p)).ok())
        })
        .as_ref()
}

/// Encode residual bytes with the global dictionary if loaded, otherwise
/// plain bw-codec.
pub fn encode_residual_with_dict(bytes: &[u8]) -> Result<Vec<u8>, BwError> {
    let opts = global_dict().map(|d| EncodeBwOptions {
        dictionary: Some(d.entries.clone()),
        ..Default::default()
    });
    encode_bw(bytes, "application/octet-stream", opts.as_ref())
}

#[cfg(test)]
mod tests {
    use super::*;
    use bitwise::bw_codec::is_bw_dict_mode;

    /// Build a synthetic `.bwdict` byte stream:
    /// magic "BWDC" + version u32 LE + count u32 LE + entry_len u32 LE + entries.
    fn make_bwdict(version: u32, count: u32, entry_len: u32, entries: &[Vec<u8>]) -> Vec<u8> {
        let mut buf = Vec::new();
        buf.extend_from_slice(b"BWDC");
        buf.extend_from_slice(&version.to_le_bytes());
        buf.extend_from_slice(&count.to_le_bytes());
        buf.extend_from_slice(&entry_len.to_le_bytes());
        for e in entries {
            buf.extend_from_slice(e);
        }
        buf
    }

    #[test]
    fn load_bwdict_round_trip() {
        let entries = vec![vec![1u8, 2, 3, 4], vec![5, 6, 7, 8], vec![9, 10, 11, 12]];
        let buf = make_bwdict(1, 3, 4, &entries);
        let dict = ResidualDict::from_bytes(&buf).expect("parse ok");
        assert_eq!(dict.entry_len, 4);
        assert_eq!(dict.entries.len(), 3);
        assert_eq!(dict.entries, entries);
    }

    #[test]
    fn load_bwdict_bad_magic_rejected() {
        let entries = vec![vec![1u8, 2, 3, 4]];
        let mut buf = make_bwdict(1, 1, 4, &entries);
        buf[0] = b'X'; // corrupt first magic byte
        match ResidualDict::from_bytes(&buf) {
            Err(DictLoadError::BadMagic) => {}
            other => panic!("expected BadMagic, got {:?}", other),
        }
    }

    #[test]
    fn load_bwdict_bad_version_rejected() {
        let entries = vec![vec![1u8, 2, 3, 4]];
        let buf = make_bwdict(2, 1, 4, &entries);
        match ResidualDict::from_bytes(&buf) {
            Err(DictLoadError::BadVersion(2)) => {}
            other => panic!("expected BadVersion(2), got {:?}", other),
        }
    }

    #[test]
    fn load_bwdict_truncated_rejected() {
        let entries = vec![vec![1u8, 2, 3, 4], vec![5, 6, 7, 8]];
        let mut buf = make_bwdict(1, 2, 4, &entries);
        // Cut last entry short by 2 bytes.
        buf.truncate(buf.len() - 2);
        match ResidualDict::from_bytes(&buf) {
            Err(DictLoadError::Truncated) => {}
            other => panic!("expected Truncated, got {:?}", other),
        }
    }

    #[test]
    fn encode_residual_without_global_dict_falls_back_to_plain_bw_codec() {
        // NOTE: GLOBAL_DICT is a process-wide OnceLock. If another test in
        // this module already initialized it, this test still works because
        // the env var is unset by default in `cargo test` — the OnceLock will
        // resolve to `None` on first read regardless of the order. We remove
        // the env var defensively in case the host shell exported one.
        // SAFETY: `remove_var` is `unsafe` in some toolchains for thread
        // races; tests in this module do not spawn threads that read the var.
        // We avoid the unsafe block by only calling it inside a test gate.
        std::env::remove_var("GNOSIS_RESIDUAL_DICT");

        let bytes: Vec<u8> = (0..64u8).collect();
        let out = encode_residual_with_dict(&bytes).expect("encode ok");

        // bw-codec magic header is the load-bearing assertion the task spec
        // pins: a valid bw-codec blob always starts with [0xb1,0xba,0xba,0xba].
        assert!(out.len() >= 4, "output too short");
        assert_eq!(&out[..4], &[0xb1u8, 0xba, 0xba, 0xba]);
    }

    /// Dict-mode wire-format test.
    ///
    /// **Helper choice (documented per task spec):** rather than mutate
    /// `GLOBAL_DICT` (an `OnceLock` — a test-only setter would require either
    /// an `unsafe` raw-pointer override or a refactor to `Mutex<Option<...>>`
    /// that pollutes the production path), this test exercises the *same*
    /// code path the wrapper takes on the dict-loaded branch by calling
    /// `encode_bw` directly with an `EncodeBwOptions { dictionary: Some(_) }`.
    /// That is byte-for-byte what `encode_residual_with_dict` produces when
    /// `global_dict()` returns `Some`. The wire-level invariant we check is
    /// that the dict-mode flag bit is raised on the version byte — verified
    /// via the public `is_bw_dict_mode` predicate.
    #[test]
    fn encode_residual_with_dict_uses_dict_mode() {
        let dict = ResidualDict {
            entry_len: 4,
            entries: vec![vec![0u8, 0, 0, 0], vec![1, 1, 1, 1]],
        };
        let opts = EncodeBwOptions {
            dictionary: Some(dict.entries.clone()),
            ..Default::default()
        };
        let bytes: Vec<u8> = (0..32u8).collect();
        let out = encode_bw(&bytes, "application/octet-stream", Some(&opts)).expect("encode ok");

        // Magic still intact.
        assert_eq!(&out[..4], &[0xb1u8, 0xba, 0xba, 0xba]);
        // Dict-mode flag raised on the version byte.
        assert!(
            is_bw_dict_mode(&out),
            "expected DICT_FLAG set on version byte"
        );
    }
}
